mapper.select:
select id, dish_id, available_stock, locked_stock, version, create_time, update_time
from dish_stock
where dish_id = #{dishId}

mapper.update:
update dish_stock
set locked_stock = locked_stock - #{quantity},
    version = version + 1
where dish_id = #{dishId}
  and locked_stock >= #{quantity}
  and #{quantity} > 0
